window.KJV1769_STRONG_BOOKS["Hos"] = {"osis":"Hos","book":"호세아","verses":{"1:1":{"text":"The word of the LORD that came unto Hosea, the son of Beeri, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and in the days of Jeroboam the son of Joash, king of Israel.","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H1954","that came unto Hosea",21,41],["H1121","the son",43,50],["H0882","of Beeri",51,59],["H3117","in the days",61,72],["H5818","of Uzziah",73,82],["H3147","Jotham",84,90],["H0271","Ahaz",92,96],["H3169","and Hezekiah",98,110],["H4428","kings",112,117],["H3063","of Judah",118,126],["H3117","and in the days",128,143],["H3379","of Jeroboam",144,155],["H1121","the son",156,163],["H3101","of Joash",164,172],["H4428","king",174,178],["H3478","of Israel",179,188]]},"1:2":{"text":"The beginning of the word of the LORD by Hosea. And the LORD said to Hosea, Go, take unto thee a wife of whoredoms and children of whoredoms: for the land hath committed great whoredom, departing from the LORD.","words":[["H8462","The beginning",0,13],["H1696","of the word",14,25],["H3068","of the LORD",26,37],["H1954","by Hosea",38,46],["H3068","And the LORD",48,60],["H0559","said",61,65],["H1954","to Hosea",66,74],["H3212","Go",76,78],["H3947","take",80,84],["H0802","unto thee a wife",85,101],["H2183","of whoredoms",102,114],["H3206","and children",115,127],["H2183","of whoredoms",128,140],["H0776","for the land",142,154],["H2181","hath committed great",155,175],["H2181","whoredom",176,184],["H0310","departing from",186,200],["H3068","the LORD",201,209]]},"1:3":{"text":"So he went and took Gomer the daughter of Diblaim; which conceived, and bare him a son.","words":[["H3212","So he went",0,10],["H3947","and took",11,19],["H1586","Gomer",20,25],["H1323","the daughter",26,38],["H1691","of Diblaim",39,49],["H2029","which conceived",51,66],["H3205","and bare",68,76],["H1121","him a son",77,86]]},"1:4":{"text":"And the LORD said unto him, Call his name Jezreel; for yet a little while, and I will avenge the blood of Jezreel upon the house of Jehu, and will cause to cease the kingdom of the house of Israel.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7121","unto him, Call",18,32],["H8034","his name",33,41],["H3157","Jezreel",42,49],["H4592","for yet a little",51,67],["H6485","while, and I will avenge",68,92],["H1818","the blood",93,102],["H3157","of Jezreel",103,113],["H1004","upon the house",114,128],["H3058","of Jehu",129,136],["H7673","and will cause to cease",138,161],["H4468","the kingdom",162,173],["H1004","of the house",174,186],["H3478","of Israel",187,196]]},"1:5":{"text":"And it shall come to pass at that day, that I will break the bow of Israel in the valley of Jezreel.","words":[["H3117","And it shall come to pass at that day",0,37],["H7665","that I will break",39,56],["H7198","the bow",57,64],["H3478","of Israel",65,74],["H6010","in the valley",75,88],["H3157","of Jezreel",89,99]]},"1:6":{"text":"And she conceived again, and bare a daughter. And God said unto him, Call her name Loruhamah: for I will no more have mercy upon the house of Israel; but I will utterly take them away.","words":[["H2029","And she conceived again",0,23],["H3205","and bare",25,33],["H1323","a daughter",34,44],["H0559","And God said",46,58],["H7121","unto him, Call",59,73],["H8034","her name",74,82],["H3819","Loruhamah",83,92],["H3254","for I will no more",94,112],["H7355","have mercy",113,123],["H1004","upon the house",124,138],["H3478","of Israel",139,148],["H5375","but I will utterly",150,168],["H5375","take them away",169,183]]},"1:7":{"text":"But I will have mercy upon the house of Judah, and will save them by the LORD their God, and will not save them by bow, nor by sword, nor by battle, by horses, nor by horsemen.","words":[["H7355","But I will have mercy",0,21],["H1004","upon the house",22,36],["H3063","of Judah",37,45],["H3467","and will save",47,60],["H3068","them by the LORD",61,77],["H0430","their God",78,87],["H3467","and will not save",89,106],["H7198","them by bow",107,118],["H2719","nor by sword",120,132],["H4421","nor by battle",134,147],["H5483","by horses",149,158],["H6571","nor by horsemen",160,175]]},"1:8":{"text":"Now when she had weaned Loruhamah, she conceived, and bare a son.","words":[["H1580","Now when she had weaned",0,23],["H3819","Loruhamah",24,33],["H2029","she conceived",35,48],["H3205","and bare",50,58],["H1121","a son",59,64]]},"1:9":{"text":"Then said God, Call his name Loammi: for ye are not my people, and I will not be your God.","words":[["H0559","Then said",0,9],["H7121","God, Call",10,19],["H8034","his name",20,28],["H3818","Loammi",29,35],["H5971","for ye are not my people",37,61]]},"1:10":{"text":"Yet the number of the children of Israel shall be as the sand of the sea, which cannot be measured nor numbered; and it shall come to pass, that in the place where it was said unto them, Ye are not my people, there it shall be said unto them, Ye are the sons of the living God.","words":[["H4557","Yet the number",0,14],["H1121","of the children",15,30],["H3478","of Israel",31,40],["H2344","shall be as the sand",41,61],["H3220","of the sea",62,72],["H4058","which cannot be measured",74,98],["H5608","nor numbered",99,111],["H4725","and it shall come to pass, that in the place",113,157],["H0559","where it was said",158,175],["H5971","unto them, Ye are not my people",176,207],["H0559","there it shall be said",209,231],["H1121","unto them, Ye are the sons",232,258],["H2416","of the living",259,272],["H0410","God",273,276]]},"1:11":{"text":"Then shall the children of Judah and the children of Israel be gathered together, and appoint themselves one head, and they shall come up out of the land: for great shall be the day of Jezreel.","words":[["H1121","Then shall the children",0,23],["H3063","of Judah",24,32],["H1121","and the children",33,49],["H3478","of Israel",50,59],["H6908","be gathered",60,71],["H3162","together",72,80],["H7760","and appoint",82,93],["H0259","themselves one",94,108],["H7218","head",109,113],["H5927","and they shall come up",115,137],["H0776","out of the land",138,153],["H1419","for great",155,164],["H3117","shall be the day",165,181],["H3157","of Jezreel",182,192]]},"2:1":{"text":"Say ye unto your brethren, Ammi; and to your sisters, Ruhamah.","words":[["H0559","Say",0,3],["H0251","ye unto your brethren",4,25],["H5971","Ammi",27,31],["H0269","and to your sisters",33,52],["H7355","Ruhamah",54,61]]},"2:2":{"text":"Plead with your mother, plead: for she is not my wife, neither am I her husband: let her therefore put away her whoredoms out of her sight, and her adulteries from between her breasts;","words":[["H7378","Plead",0,5],["H0517","with your mother",6,22],["H7378","plead",24,29],["H0802","for she is not my wife",31,53],["H0376","neither am I her husband",55,79],["H5493","let her therefore put away",81,107],["H2183","her whoredoms",108,121],["H6440","out of her sight",122,138],["H5005","and her adulteries",140,158],["H7699","from between her breasts",159,183]]},"2:3":{"text":"Lest I strip her naked, and set her as in the day that she was born, and make her as a wilderness, and set her like a dry land, and slay her with thirst.","words":[["H6584","Lest I strip",0,12],["H6174","her naked",13,22],["H3322","and set",24,31],["H3117","her as in the day",32,49],["H3205","that she was born",50,67],["H7760","and make",69,77],["H4057","her as a wilderness",78,97],["H7896","and set",99,106],["H6723","her like a dry",107,121],["H0776","land",122,126],["H4191","and slay",128,136],["H6772","her with thirst",137,152]]},"2:4":{"text":"And I will not have mercy upon her children; for they be the children of whoredoms.","words":[["H7355","And I will not have mercy",0,25],["H1121","upon her children",26,43],["H1121","for they be the children",45,69],["H2183","of whoredoms",70,82]]},"2:5":{"text":"For their mother hath played the harlot: she that conceived them hath done shamefully: for she said, I will go after my lovers, that give me my bread and my water, my wool and my flax, mine oil and my drink.","words":[["H0517","For their mother",0,16],["H2181","hath played the harlot",17,39],["H2029","she that conceived",41,59],["H3001","them hath done shamefully",60,85],["H0559","for she said",87,99],["H3212","I will go",101,110],["H0310","after",111,116],["H0157","my lovers",117,126],["H5414","that give",128,137],["H3899","me my bread",138,149],["H4325","and my water",150,162],["H6785","my wool",164,171],["H6593","and my flax",172,183],["H8081","mine oil",185,193],["H8250","and my drink",194,206]]},"2:6":{"text":"Therefore, behold, I will hedge up thy way with thorns, and make a wall, that she shall not find her paths.","words":[["H7753","Therefore, behold, I will hedge",0,31],["H1870","up thy way",32,42],["H5518","with thorns",43,54],["H1443","and make",56,64],["H1447","a wall",65,71],["H4672","that she shall not find",73,96],["H5410","her paths",97,106]]},"2:7":{"text":"And she shall follow after her lovers, but she shall not overtake them; and she shall seek them, but shall not find them: then shall she say, I will go and return to my first husband; for then was it better with me than now.","words":[["H7291","And she shall follow",0,20],["H0157","after her lovers",21,37],["H5381","but she shall not overtake",39,65],["H1245","them; and she shall seek",66,90],["H4672","them, but shall not find",91,115],["H0559","them: then shall she say",116,140],["H3212","I will go",142,151],["H7725","and return",152,162],["H7223","to my first",163,174],["H0376","husband",175,182],["H2896","for then was it better",184,206],["H6258","with me than now",207,223]]},"2:8":{"text":"For she did not know that I gave her corn, and wine, and oil, and multiplied her silver and gold, which they prepared for Baal.","words":[["H3045","For she did not know",0,20],["H5414","that I gave",21,32],["H1715","her corn",33,41],["H8492","and wine",43,51],["H3323","and oil",53,60],["H7235","and multiplied",62,76],["H3701","her silver",77,87],["H2091","and gold",88,96],["H6213","which they prepared",98,117],["H1168","for Baal",118,126]]},"2:9":{"text":"Therefore will I return, and take away my corn in the time thereof, and my wine in the season thereof, and will recover my wool and my flax given to cover her nakedness.","words":[["H7725","Therefore will I return",0,23],["H3947","and take away",25,38],["H1715","my corn",39,46],["H6256","in the time",47,58],["H8492","thereof, and my wine",59,79],["H4150","in the season",80,93],["H5337","thereof, and will recover",94,119],["H6785","my wool",120,127],["H6593","and my flax",128,139],["H3680","given to cover",140,154],["H6172","her nakedness",155,168]]},"2:10":{"text":"And now will I discover her lewdness in the sight of her lovers, and none shall deliver her out of mine hand.","words":[["H1540","And now will I discover",0,23],["H5040","her lewdness",24,36],["H5869","in the sight",37,49],["H0157","of her lovers",50,63],["H0376","and none",65,73],["H5337","shall deliver",74,87],["H3027","her out of mine hand",88,108]]},"2:11":{"text":"I will also cause all her mirth to cease, her feast days, her new moons, and her sabbaths, and all her solemn feasts.","words":[["H4885","I will also cause all her mirth",0,31],["H7673","to cease",32,40],["H2282","her feast days",42,56],["H2320","her new moons",58,71],["H7676","and her sabbaths",73,89],["H4150","and all her solemn feasts",91,116]]},"2:12":{"text":"And I will destroy her vines and her fig trees, whereof she hath said, These are my rewards that my lovers have given me: and I will make them a forest, and the beasts of the field shall eat them.","words":[["H8074","And I will destroy",0,18],["H1612","her vines",19,28],["H8384","and her fig trees",29,46],["H0559","whereof she hath said",48,69],["H0866","These are my rewards",71,91],["H0157","that my lovers",92,106],["H5414","have given",107,117],["H7760","me: and I will make",118,137],["H3293","them a forest",138,151],["H2416","and the beasts",153,167],["H7704","of the field",168,180],["H0398","shall eat",181,190]]},"2:13":{"text":"And I will visit upon her the days of Baalim, wherein she burned incense to them, and she decked herself with her earrings and her jewels, and she went after her lovers, and forgat me, saith the LORD.","words":[["H6485","And I will visit",0,16],["H3117","upon her the days",17,34],["H1168","of Baalim",35,44],["H6999","wherein she burned incense",46,72],["H5710","to them, and she decked",73,96],["H5141","herself with her earrings",97,122],["H2484","and her jewels",123,137],["H3212","and she went",139,151],["H0310","after",152,157],["H0157","her lovers",158,168],["H7911","and forgat",170,180],["H5002","me, saith",181,190],["H3068","the LORD",191,199]]},"2:14":{"text":"Therefore, behold, I will allure her, and bring her into the wilderness, and speak comfortably unto her.","words":[["H6601","Therefore, behold, I will allure",0,32],["H3212","her, and bring",33,47],["H4057","her into the wilderness",48,71],["H1696","and speak",73,82],["H3820","comfortably",83,94]]},"2:15":{"text":"And I will give her her vineyards from thence, and the valley of Achor for a door of hope: and she shall sing there, as in the days of her youth, and as in the day when she came up out of the land of Egypt.","words":[["H5414","And I will give",0,15],["H3754","her her vineyards",16,33],["H6010","from thence, and the valley",34,61],["H5911","of Achor",62,70],["H6607","for a door",71,81],["H8615","of hope",82,89],["H6030","and she shall sing",91,109],["H3117","there, as in the days",110,131],["H5271","of her youth",132,144],["H3117","and as in the day",146,163],["H5927","when she came up",164,180],["H0776","out of the land",181,196],["H4714","of Egypt",197,205]]},"2:16":{"text":"And it shall be at that day, saith the LORD, that thou shalt call me Ishi; and shalt call me no more Baali.","words":[["H3117","And it shall be at that day",0,27],["H5002","saith",29,34],["H3068","the LORD",35,43],["H7121","that thou shalt call",45,65],["H0376","me Ishi",66,73],["H7121","and shalt call",75,89],["H1180","me no more Baali",90,106]]},"2:17":{"text":"For I will take away the names of Baalim out of her mouth, and they shall no more be remembered by their name.","words":[["H5493","For I will take away",0,20],["H8034","the names",21,30],["H1168","of Baalim",31,40],["H6310","out of her mouth",41,57],["H2142","and they shall no more be remembered",59,95],["H8034","by their name",96,109]]},"2:18":{"text":"And in that day will I make a covenant for them with the beasts of the field, and with the fowls of heaven, and with the creeping things of the ground: and I will break the bow and the sword and the battle out of the earth, and will make them to lie down safely.","words":[["H3117","And in that day",0,15],["H3772","will I make",16,27],["H1285","a covenant",28,38],["H2416","for them with the beasts",39,63],["H7704","of the field",64,76],["H5775","and with the fowls",78,96],["H8064","of heaven",97,106],["H7431","and with the creeping things",108,136],["H0127","of the ground",137,150],["H7665","and I will break",152,168],["H7198","the bow",169,176],["H2719","and the sword",177,190],["H4421","and the battle",191,205],["H0776","out of the earth",206,222],["H7901","and will make them to lie down",224,254],["H0983","safely",255,261]]},"2:19":{"text":"And I will betroth thee unto me for ever; yea, I will betroth thee unto me in righteousness, and in judgment, and in lovingkindness, and in mercies.","words":[["H0781","And I will betroth",0,18],["H5769","thee unto me for ever",19,40],["H0781","yea, I will betroth",42,61],["H6664","thee unto me in righteousness",62,91],["H4941","and in judgment",93,108],["H2617","and in lovingkindness",110,131],["H7356","and in mercies",133,147]]},"2:20":{"text":"I will even betroth thee unto me in faithfulness: and thou shalt know the LORD.","words":[["H0781","I will even betroth",0,19],["H0530","thee unto me in faithfulness",20,48],["H3045","and thou shalt know",50,69],["H3068","the LORD",70,78]]},"2:21":{"text":"And it shall come to pass in that day, I will hear, saith the LORD, I will hear the heavens, and they shall hear the earth;","words":[["H3117","And it shall come to pass in that day",0,37],["H6030","I will hear",39,50],["H5002","saith",52,57],["H3068","the LORD",58,66],["H6030","I will hear",68,79],["H8064","the heavens",80,91],["H6030","and they shall hear",93,112],["H0776","the earth",113,122]]},"2:22":{"text":"And the earth shall hear the corn, and the wine, and the oil; and they shall hear Jezreel.","words":[["H0776","And the earth",0,13],["H6030","shall hear",14,24],["H1715","the corn",25,33],["H8492","and the wine",35,47],["H3323","and the oil",49,60],["H6030","and they shall hear",62,81],["H3157","Jezreel",82,89]]},"2:23":{"text":"And I will sow her unto me in the earth; and I will have mercy upon her that had not obtained mercy; and I will say to them which were not my people, Thou art my people; and they shall say, Thou art my God.","words":[["H2232","And I will sow",0,14],["H0776","her unto me in the earth",15,39],["H7355","and I will have mercy",41,62],["H7355","upon her that had not obtained mercy",63,99],["H3818","upon her that had not obtained mercy",63,99],["H0559","and I will say",101,115],["H5971","to them which were not my people",116,148],["H5971","Thou art my people",150,168],["H0559","and they shall say",170,188],["H0430","Thou art my God",190,205]]},"3:1":{"text":"Then said the LORD unto me, Go yet, love a woman beloved of her friend, yet an adulteress, according to the love of the LORD toward the children of Israel, who look to other gods, and love flagons of wine.","words":[["H0559","Then said",0,9],["H3068","the LORD",10,18],["H3212","unto me, Go",19,30],["H0157","yet, love",31,40],["H0802","a woman",41,48],["H0157","beloved",49,56],["H7453","of her friend",57,70],["H5003","yet an adulteress",72,89],["H0160","according to the love",91,112],["H3068","of the LORD",113,124],["H1121","toward the children",125,144],["H3478","of Israel",145,154],["H6437","who look",156,164],["H0312","to other",165,173],["H0430","gods",174,178],["H0157","and love",180,188],["H0809","flagons",189,196],["H6025","of wine",197,204]]},"3:2":{"text":"So I bought her to me for fifteen pieces of silver, and for an homer of barley, and an half homer of barley:","words":[["H3739","So I bought",0,11],["H6240","her to me for fifteen",12,33],["H2568","her to me for fifteen",12,33],["H3701","pieces of silver",34,50],["H2563","and for an homer",52,68],["H8184","of barley",69,78],["H3963","and an half homer",80,97],["H8184","of barley",98,107]]},"3:3":{"text":"And I said unto her, Thou shalt abide for me many days; thou shalt not play the harlot, and thou shalt not be for another man: so will I also be for thee.","words":[["H0559","And I said",0,10],["H3427","unto her, Thou shalt abide",11,37],["H7227","for me many",38,49],["H3117","days",50,54],["H2181","thou shalt not play the harlot",56,86],["H1961","and thou shalt not be",88,109],["H0376","for another man",110,125]]},"3:4":{"text":"For the children of Israel shall abide many days without a king, and without a prince, and without a sacrifice, and without an image, and without an ephod, and without teraphim:","words":[["H1121","For the children",0,16],["H3478","of Israel",17,26],["H3427","shall abide",27,38],["H7227","many",39,43],["H3117","days",44,48],["H4428","without a king",49,63],["H8269","and without a prince",65,85],["H2077","and without a sacrifice",87,110],["H4676","and without an image",112,132],["H0646","and without an ephod",134,154],["H8655","and without teraphim",156,176]]},"3:5":{"text":"Afterward shall the children of Israel return, and seek the LORD their God, and David their king; and shall fear the LORD and his goodness in the latter days.","words":[["H0310","Afterward",0,9],["H1121","shall the children",10,28],["H3478","of Israel",29,38],["H7725","return",39,45],["H1245","and seek",47,55],["H3068","the LORD",56,64],["H0430","their God",65,74],["H1732","and David",76,85],["H4428","their king",86,96],["H6342","and shall fear",98,112],["H3068","the LORD",113,121],["H2898","and his goodness",122,138],["H0319","in the latter",139,152],["H3117","days",153,157]]},"4:1":{"text":"Hear the word of the LORD, ye children of Israel: for the LORD hath a controversy with the inhabitants of the land, because there is no truth, nor mercy, nor knowledge of God in the land.","words":[["H8085","Hear",0,4],["H1697","the word",5,13],["H3068","of the LORD",14,25],["H1121","ye children",27,38],["H3478","of Israel",39,48],["H3068","for the LORD",50,62],["H7379","hath a controversy",63,81],["H3427","with the inhabitants",82,102],["H0776","of the land",103,114],["H0571","because there is no truth",116,141],["H2617","nor mercy",143,152],["H1847","nor knowledge",154,167],["H0430","of God",168,174],["H0776","in the land",175,186]]},"4:2":{"text":"By swearing, and lying, and killing, and stealing, and committing adultery, they break out, and blood toucheth blood.","words":[["H0422","By swearing",0,11],["H3584","and lying",13,22],["H7523","and killing",24,35],["H1589","and stealing",37,49],["H5003","and committing adultery",51,74],["H6555","they break out",76,90],["H1818","and blood",92,101],["H5060","toucheth",102,110],["H1818","blood",111,116]]},"4:3":{"text":"Therefore shall the land mourn, and every one that dwelleth therein shall languish, with the beasts of the field, and with the fowls of heaven; yea, the fishes of the sea also shall be taken away.","words":[["H0776","Therefore shall the land",0,24],["H0056","mourn",25,30],["H3427","and every one that dwelleth",32,59],["H0535","therein shall languish",60,82],["H2416","with the beasts",84,99],["H7704","of the field",100,112],["H5775","and with the fowls",114,132],["H8064","of heaven",133,142],["H1709","yea, the fishes",144,159],["H3220","of the sea",160,170],["H0622","also shall be taken away",171,195]]},"4:4":{"text":"Yet let no man strive, nor reprove another: for thy people are as they that strive with the priest.","words":[["H0376","Yet let no man",0,14],["H7378","strive",15,21],["H3198","nor reprove",23,34],["H0376","another",35,42],["H5971","for thy people",44,58],["H7378","are as they that strive",59,82],["H3548","with the priest",83,98]]},"4:5":{"text":"Therefore shalt thou fall in the day, and the prophet also shall fall with thee in the night, and I will destroy thy mother.","words":[["H3782","Therefore shalt thou fall",0,25],["H3117","in the day",26,36],["H5030","and the prophet",38,53],["H3782","also shall fall",54,69],["H3915","with thee in the night",70,92],["H1820","and I will destroy",94,112],["H0517","thy mother",113,123]]},"4:6":{"text":"My people are destroyed for lack of knowledge: because thou hast rejected knowledge, I will also reject thee, that thou shalt be no priest to me: seeing thou hast forgotten the law of thy God, I will also forget thy children.","words":[["H5971","My people",0,9],["H1820","are destroyed",10,23],["H1847","for lack of knowledge",24,45],["H3988","because thou hast rejected",47,73],["H1847","knowledge",74,83],["H3988","I will also reject",85,103],["H3547","thee, that thou shalt be no priest",104,138],["H7911","to me: seeing thou hast forgotten",139,172],["H8451","the law",173,180],["H0430","of thy God",181,191],["H7911","I will also forget",193,211],["H1121","thy children",212,224]]},"4:7":{"text":"As they were increased, so they sinned against me: therefore will I change their glory into shame.","words":[["H7230","As they were increased",0,22],["H2398","so they sinned",24,38],["H4171","against me: therefore will I change",39,74],["H3519","their glory",75,86],["H7036","into shame",87,97]]},"4:8":{"text":"They eat up the sin of my people, and they set their heart on their iniquity.","words":[["H0398","They eat up",0,11],["H2403","the sin",12,19],["H5971","of my people",20,32],["H5375","and they set",34,46],["H5315","their heart",47,58],["H5771","on their iniquity",59,76]]},"4:9":{"text":"And there shall be, like people, like priest: and I will punish them for their ways, and reward them their doings.","words":[["H5971","And there shall be, like people",0,31],["H3548","like priest",33,44],["H6485","and I will punish",46,63],["H1870","them for their ways",64,83],["H7725","and reward",85,95],["H4611","them their doings",96,113]]},"4:10":{"text":"For they shall eat, and not have enough: they shall commit whoredom, and shall not increase: because they have left off to take heed to the LORD.","words":[["H0398","For they shall eat",0,18],["H7646","and not have enough",20,39],["H2181","they shall commit whoredom",41,67],["H6555","and shall not increase",69,91],["H5800","because they have left off",93,119],["H8104","to take heed",120,132],["H3068","to the LORD",133,144]]},"4:11":{"text":"Whoredom and wine and new wine take away the heart.","words":[["H2184","Whoredom",0,8],["H3196","and wine",9,17],["H8492","and new wine",18,30],["H3947","take away",31,40],["H3820","the heart",41,50]]},"4:12":{"text":"My people ask counsel at their stocks, and their staff declareth unto them: for the spirit of whoredoms hath caused them to err, and they have gone a whoring from under their God.","words":[["H5971","My people",0,9],["H7592","ask",10,13],["H6086","counsel at their stocks",14,37],["H4731","and their staff",39,54],["H5046","declareth",55,64],["H7307","unto them: for the spirit",65,90],["H2183","of whoredoms",91,103],["H8582","hath caused them to err",104,127],["H2181","and they have gone a whoring",129,157],["H0430","from under their God",158,178]]},"4:13":{"text":"They sacrifice upon the tops of the mountains, and burn incense upon the hills, under oaks and poplars and elms, because the shadow thereof is good: therefore your daughters shall commit whoredom, and your spouses shall commit adultery.","words":[["H2076","They sacrifice",0,14],["H7218","upon the tops",15,28],["H2022","of the mountains",29,45],["H6999","and burn incense",47,63],["H1389","upon the hills",64,78],["H0437","under oaks",80,90],["H3839","and poplars",91,102],["H0424","and elms",103,111],["H6738","because the shadow",113,131],["H2896","thereof is good",132,147],["H1323","therefore your daughters",149,173],["H2181","shall commit whoredom",174,195],["H3618","and your spouses",197,213],["H5003","shall commit adultery",214,235]]},"4:14":{"text":"I will not punish your daughters when they commit whoredom, nor your spouses when they commit adultery: for themselves are separated with whores, and they sacrifice with harlots: therefore the people that doth not understand shall fall.","words":[["H6485","I will not punish",0,17],["H1323","your daughters",18,32],["H2181","when they commit whoredom",33,58],["H3618","nor your spouses",60,76],["H5003","when they commit adultery",77,102],["H6504","for themselves are separated",104,132],["H2181","with whores",133,144],["H2076","and they sacrifice",146,164],["H6948","with harlots",165,177],["H5971","therefore the people",179,199],["H0995","that doth not understand",200,224],["H3832","shall fall",225,235]]},"4:15":{"text":"Though thou, Israel, play the harlot, yet let not Judah offend; and come not ye unto Gilgal, neither go ye up to Bethaven, nor swear, The LORD liveth.","words":[["H3478","Though thou, Israel",0,19],["H2181","play the harlot",21,36],["H3063","yet let not Judah",38,55],["H0816","offend",56,62],["H0935","and come",64,72],["H1537","not ye unto Gilgal",73,91],["H5927","neither go ye up",93,109],["H1007","to Bethaven",110,121],["H7650","nor swear",123,132],["H3068","The LORD",134,142],["H2416","liveth",143,149]]},"4:16":{"text":"For Israel slideth back as a backsliding heifer: now the LORD will feed them as a lamb in a large place.","words":[["H3478","For Israel",0,10],["H5637","slideth back",11,23],["H5637","as a backsliding",24,40],["H6510","heifer",41,47],["H3068","now the LORD",49,61],["H7462","will feed",62,71],["H3532","them as a lamb",72,86],["H4800","in a large place",87,103]]},"4:17":{"text":"Ephraim is joined to idols: let him alone.","words":[["H0669","Ephraim",0,7],["H2266","is joined",8,17],["H6091","to idols",18,26],["H3240","let him alone",28,41]]},"4:18":{"text":"Their drink is sour: they have committed whoredom continually: her rulers with shame do love, Give ye.","words":[["H5435","Their drink",0,11],["H5493","is sour",12,19],["H2181","they have committed whoredom",21,49],["H2181","continually",50,61],["H4043","her rulers",63,73],["H7036","with shame",74,84],["H0157","do love",85,92],["H3051","Give",94,98]]},"4:19":{"text":"The wind hath bound her up in her wings, and they shall be ashamed because of their sacrifices.","words":[["H7307","The wind",0,8],["H6887","hath bound her up",9,26],["H3671","in her wings",27,39],["H0954","and they shall be ashamed",41,66],["H2077","because of their sacrifices",67,94]]},"5:1":{"text":"Hear ye this, O priests; and hearken, ye house of Israel; and give ye ear, O house of the king; for judgment is toward you, because ye have been a snare on Mizpah, and a net spread upon Tabor.","words":[["H8085","Hear",0,4],["H3548","ye this, O priests",5,23],["H7181","and hearken",25,36],["H1004","ye house",38,46],["H3478","of Israel",47,56],["H0238","and give ye ear",58,73],["H1004","O house",75,82],["H4428","of the king",83,94],["H4941","for judgment",96,108],["H6341","is toward you, because ye have been a snare",109,152],["H4709","on Mizpah",153,162],["H7568","and a net",164,173],["H6566","spread",174,180],["H8396","upon Tabor",181,191]]},"5:2":{"text":"And the revolters are profound to make slaughter, though I have been a rebuker of them all.","words":[["H7846","And the revolters",0,17],["H6009","are profound",18,30],["H7819","to make slaughter",31,48],["H4148","though I have been a rebuker",50,78]]},"5:3":{"text":"I know Ephraim, and Israel is not hid from me: for now, O Ephraim, thou committest whoredom, and Israel is defiled.","words":[["H3045","I know",0,6],["H0669","Ephraim",7,14],["H3478","and Israel",16,26],["H3582","is not hid",27,37],["H0669","from me: for now, O Ephraim",38,65],["H2181","thou committest whoredom",67,91],["H3478","and Israel",93,103],["H2930","is defiled",104,114]]},"5:4":{"text":"They will not frame their doings to turn unto their God: for the spirit of whoredoms is in the midst of them, and they have not known the LORD.","words":[["H5414","They will not frame",0,19],["H4611","their doings",20,32],["H7725","to turn",33,40],["H0430","unto their God",41,55],["H7307","for the spirit",57,71],["H2183","of whoredoms",72,84],["H7130","is in the midst",85,100],["H3045","of them, and they have not known",101,133],["H3068","the LORD",134,142]]},"5:5":{"text":"And the pride of Israel doth testify to his face: therefore shall Israel and Ephraim fall in their iniquity; Judah also shall fall with them.","words":[["H1347","And the pride",0,13],["H3478","of Israel",14,23],["H6030","doth testify",24,36],["H6440","to his face",37,48],["H3478","therefore shall Israel",50,72],["H0669","and Ephraim",73,84],["H3782","fall",85,89],["H5771","in their iniquity",90,107],["H3063","Judah",109,114],["H3782","also shall fall",115,130]]},"5:6":{"text":"They shall go with their flocks and with their herds to seek the LORD; but they shall not find him; he hath withdrawn himself from them.","words":[["H3212","They shall go",0,13],["H6629","with their flocks",14,31],["H1241","and with their herds",32,52],["H1245","to seek",53,60],["H3068","the LORD",61,69],["H4672","but they shall not find",71,94],["H2502","him; he hath withdrawn",95,117]]},"5:7":{"text":"They have dealt treacherously against the LORD: for they have begotten strange children: now shall a month devour them with their portions.","words":[["H0898","They have dealt treacherously",0,29],["H3068","against the LORD",30,46],["H3205","for they have begotten",48,70],["H2114","strange",71,78],["H1121","children",79,87],["H2320","now shall a month",89,106],["H0398","devour",107,113],["H2506","them with their portions",114,138]]},"5:8":{"text":"Blow ye the cornet in Gibeah, and the trumpet in Ramah: cry aloud at Bethaven, after thee, O Benjamin.","words":[["H8628","Blow",0,4],["H7782","ye the cornet",5,18],["H1390","in Gibeah",19,28],["H2689","and the trumpet",30,45],["H7414","in Ramah",46,54],["H7321","cry aloud",56,65],["H1007","at Bethaven",66,77],["H0310","after",79,84],["H1144","thee, O Benjamin",85,101]]},"5:9":{"text":"Ephraim shall be desolate in the day of rebuke: among the tribes of Israel have I made known that which shall surely be.","words":[["H0669","Ephraim",0,7],["H8047","shall be desolate",8,25],["H3117","in the day",26,36],["H8433","of rebuke",37,46],["H7626","among the tribes",48,64],["H3478","of Israel",65,74],["H3045","have I made known",75,92],["H0539","that which shall surely be",93,119]]},"5:10":{"text":"The princes of Judah were like them that remove the bound: therefore I will pour out my wrath upon them like water.","words":[["H8269","The princes",0,11],["H3063","of Judah",12,20],["H5253","were like them that remove",21,47],["H1366","the bound",48,57],["H8210","therefore I will pour out",59,84],["H5678","my wrath",85,93],["H4325","upon them like water",94,114]]},"5:11":{"text":"Ephraim is oppressed and broken in judgment, because he willingly walked after the commandment.","words":[["H0669","Ephraim",0,7],["H6231","is oppressed",8,20],["H7533","and broken",21,31],["H4941","in judgment",32,43],["H2974","because he willingly",45,65],["H1980","walked",66,72],["H0310","after",73,78],["H6673","the commandment",79,94]]},"5:12":{"text":"Therefore will I be unto Ephraim as a moth, and to the house of Judah as rottenness.","words":[["H0669","Therefore will I be unto Ephraim",0,32],["H6211","as a moth",33,42],["H1004","and to the house",44,60],["H3063","of Judah",61,69],["H7538","as rottenness",70,83]]},"5:13":{"text":"When Ephraim saw his sickness, and Judah saw his wound, then went Ephraim to the Assyrian, and sent to king Jareb: yet could he not heal you, nor cure you of your wound.","words":[["H0669","When Ephraim",0,12],["H7200","saw",13,16],["H2483","his sickness",17,29],["H3063","and Judah",31,40],["H4205","saw his wound",41,54],["H3212","then went",56,65],["H0669","Ephraim",66,73],["H0804","to the Assyrian",74,89],["H7971","and sent",91,99],["H4428","to king",100,107],["H3377","Jareb",108,113],["H7378","Jareb",108,113],["H3201","yet could",115,124],["H7495","he not heal",125,136],["H1455","you, nor cure",137,150],["H4205","you of your wound",151,168]]},"5:14":{"text":"For I will be unto Ephraim as a lion, and as a young lion to the house of Judah: I, even I, will tear and go away; I will take away, and none shall rescue him.","words":[["H0669","For I will be unto Ephraim",0,26],["H7826","as a lion",27,36],["H3715","and as a young lion",38,57],["H1004","to the house",58,70],["H3063","of Judah",71,79],["H2963","I, even I, will tear",81,101],["H3212","and go away",102,113],["H5375","I will take away",115,131],["H5337","and none shall rescue",133,154]]},"5:15":{"text":"I will go and return to my place, till they acknowledge their offence, and seek my face: in their affliction they will seek me early.","words":[["H3212","I will go",0,9],["H7725","and return",10,20],["H4725","to my place",21,32],["H0816","till they acknowledge their offence",34,69],["H1245","and seek",71,79],["H6440","my face",80,87],["H6862","in their affliction",89,108],["H7836","they will seek me early",109,132]]},"6:1":{"text":"Come, and let us return unto the LORD: for he hath torn, and he will heal us; he hath smitten, and he will bind us up.","words":[["H3212","Come",0,4],["H7725","and let us return",6,23],["H3068","unto the LORD",24,37],["H2963","for he hath torn",39,55],["H7495","and he will heal",57,73],["H5221","us; he hath smitten",74,93],["H2280","and he will bind us up",95,117]]},"6:2":{"text":"After two days will he revive us: in the third day he will raise us up, and we shall live in his sight.","words":[["H3117","After two days",0,14],["H2421","will he revive",15,29],["H7992","us: in the third",30,46],["H3117","day",47,50],["H6965","he will raise us up",51,70],["H2421","and we shall live",72,89],["H6440","in his sight",90,102]]},"6:3":{"text":"Then shall we know, if we follow on to know the LORD: his going forth is prepared as the morning; and he shall come unto us as the rain, as the latter and former rain unto the earth.","words":[["H3045","Then shall we know",0,18],["H7291","if we follow",20,32],["H3045","on to know",33,43],["H3068","the LORD",44,52],["H4161","his going forth",54,69],["H3559","is prepared",70,81],["H7837","as the morning",82,96],["H0935","and he shall come",98,115],["H1653","unto us as the rain",116,135],["H4456","as the latter",137,150],["H3384","and former rain",151,166],["H0776","unto the earth",167,181]]},"6:4":{"text":"O Ephraim, what shall I do unto thee? O Judah, what shall I do unto thee? for your goodness is as a morning cloud, and as the early dew it goeth away.","words":[["H0669","O Ephraim",0,9],["H6213","what shall I do",11,26],["H3063","unto thee? O Judah",27,45],["H6213","what shall I do",47,62],["H2617","unto thee? for your goodness",63,91],["H1242","is as a morning",92,107],["H6051","cloud",108,113],["H7925","and as the early",115,131],["H2919","dew",132,135],["H1980","it goeth away",136,149]]},"6:5":{"text":"Therefore have I hewed them by the prophets; I have slain them by the words of my mouth: and thy judgments are as the light that goeth forth.","words":[["H2672","Therefore have I hewed",0,22],["H5030","them by the prophets",23,43],["H2026","I have slain",45,57],["H0561","them by the words",58,75],["H6310","of my mouth",76,87],["H4941","and thy judgments",89,106],["H0216","are as the light",107,123],["H3318","that goeth forth",124,140]]},"6:6":{"text":"For I desired mercy, and not sacrifice; and the knowledge of God more than burnt offerings.","words":[["H2654","For I desired",0,13],["H2617","mercy",14,19],["H2077","and not sacrifice",21,38],["H1847","and the knowledge",40,57],["H0430","of God",58,64],["H5930","more than burnt offerings",65,90]]},"6:7":{"text":"But they like men have transgressed the covenant: there have they dealt treacherously against me.","words":[["H0120","But they like men",0,17],["H5674","have transgressed",18,35],["H1285","the covenant",36,48],["H0898","there have they dealt treacherously",50,85]]},"6:8":{"text":"Gilead is a city of them that work iniquity, and is polluted with blood.","words":[["H1568","Gilead",0,6],["H7151","is a city",7,16],["H6466","of them that work",17,34],["H0205","iniquity",35,43],["H6121","and is polluted",45,60],["H1818","with blood",61,71]]},"6:9":{"text":"And as troops of robbers wait for a man, so the company of priests murder in the way by consent: for they commit lewdness.","words":[["H1416","And as troops",0,13],["H2442","of robbers wait",14,29],["H0376","for a man",30,39],["H2267","so the company",41,55],["H3548","of priests",56,66],["H7523","murder",67,73],["H1870","in the way",74,84],["H7926","by consent",85,95],["H7927","by consent",85,95],["H6213","for they commit",97,112],["H2154","lewdness",113,121]]},"6:10":{"text":"I have seen an horrible thing in the house of Israel: there is the whoredom of Ephraim, Israel is defiled.","words":[["H7200","I have seen",0,11],["H8186","an horrible thing",12,29],["H1004","in the house",30,42],["H3478","of Israel",43,52],["H2184","there is the whoredom",54,75],["H0669","of Ephraim",76,86],["H3478","Israel",88,94],["H2930","is defiled",95,105]]},"6:11":{"text":"Also, O Judah, he hath set an harvest for thee, when I returned the captivity of my people.","words":[["H3063","Also, O Judah",0,13],["H7896","he hath set",15,26],["H7105","an harvest",27,37],["H7725","for thee, when I returned",38,63],["H7622","the captivity",64,77],["H5971","of my people",78,90]]},"7:1":{"text":"When I would have healed Israel, then the iniquity of Ephraim was discovered, and the wickedness of Samaria: for they commit falsehood; and the thief cometh in, and the troop of robbers spoileth without.","words":[["H7495","When I would have healed",0,24],["H3478","Israel",25,31],["H5771","then the iniquity",33,50],["H0669","of Ephraim",51,61],["H1540","was discovered",62,76],["H7451","and the wickedness",78,96],["H8111","of Samaria",97,107],["H6466","for they commit",109,124],["H8267","falsehood",125,134],["H1590","and the thief",136,149],["H0935","cometh in",150,159],["H1416","and the troop",161,174],["H6584","of robbers spoileth",175,194],["H2351","without",195,202]]},"7:2":{"text":"And they consider not in their hearts that I remember all their wickedness: now their own doings have beset them about; they are before my face.","words":[["H0559","And they consider",0,17],["H3824","not in their hearts",18,37],["H2142","that I remember",38,53],["H7451","all their wickedness",54,74],["H4611","now their own doings",76,96],["H5437","have beset them about",97,118],["H6440","they are before my face",120,143]]},"7:3":{"text":"They make the king glad with their wickedness, and the princes with their lies.","words":[["H4428","They make the king",0,18],["H8055","glad",19,23],["H7451","with their wickedness",24,45],["H8269","and the princes",47,62],["H3585","with their lies",63,78]]},"7:4":{"text":"They are all adulterers, as an oven heated by the baker, who ceaseth from raising after he hath kneaded the dough, until it be leavened.","words":[["H5003","They are all adulterers",0,23],["H8574","as an oven",25,35],["H1197","heated",36,42],["H0644","by the baker",43,55],["H7673","who ceaseth",57,68],["H5782","from raising",69,81],["H3888","after he hath kneaded",82,103],["H1217","the dough",104,113],["H2556","until it be leavened",115,135]]},"7:5":{"text":"In the day of our king the princes have made him sick with bottles of wine; he stretched out his hand with scorners.","words":[["H3117","In the day",0,10],["H4428","of our king",11,22],["H8269","the princes",23,34],["H2470","have made him sick",35,53],["H2534","with bottles",54,66],["H3196","of wine",67,74],["H4900","he stretched out",76,92],["H3027","his hand",93,101],["H3945","with scorners",102,115]]},"7:6":{"text":"For they have made ready their heart like an oven, whiles they lie in wait: their baker sleepeth all the night; in the morning it burneth as a flaming fire.","words":[["H7126","For they have made ready",0,24],["H3820","their heart",25,36],["H8574","like an oven",37,49],["H0693","whiles they lie in wait",51,74],["H0644","their baker",76,87],["H3463","sleepeth",88,96],["H3915","all the night",97,110],["H1242","in the morning",112,126],["H1197","it burneth",127,137],["H3852","as a flaming",138,150],["H0784","fire",151,155]]},"7:7":{"text":"They are all hot as an oven, and have devoured their judges; all their kings are fallen: there is none among them that calleth unto me.","words":[["H2552","They are all hot",0,16],["H8574","as an oven",17,27],["H0398","and have devoured",29,46],["H8199","their judges",47,59],["H4428","all their kings",61,76],["H5307","are fallen",77,87],["H7121","there is none among them that calleth",89,126]]},"7:8":{"text":"Ephraim, he hath mixed himself among the people; Ephraim is a cake not turned.","words":[["H0669","Ephraim",0,7],["H1101","he hath mixed",9,22],["H5971","himself among the people",23,47],["H0669","Ephraim",49,56],["H5692","is a cake",57,66],["H2015","not turned",67,77]]},"7:9":{"text":"Strangers have devoured his strength, and he knoweth it not: yea, gray hairs are here and there upon him, yet he knoweth not.","words":[["H2114","Strangers",0,9],["H0398","have devoured",10,23],["H3581","his strength",24,36],["H3045","and he knoweth",38,52],["H7872","it not: yea, gray hairs",53,76],["H2236","are here and there",77,95],["H3045","upon him, yet he knoweth",96,120]]},"7:10":{"text":"And the pride of Israel testifieth to his face: and they do not return to the LORD their God, nor seek him for all this.","words":[["H1347","And the pride",0,13],["H3478","of Israel",14,23],["H6030","testifieth",24,34],["H6440","to his face",35,46],["H7725","and they do not return",48,70],["H3068","to the LORD",71,82],["H0430","their God",83,92],["H1245","nor seek",94,102]]},"7:11":{"text":"Ephraim also is like a silly dove without heart: they call to Egypt, they go to Assyria.","words":[["H0669","Ephraim",0,7],["H6601","also is like a silly",8,28],["H3123","dove",29,33],["H3820","without heart",34,47],["H7121","they call",49,58],["H4714","to Egypt",59,67],["H1980","they go",69,76],["H0804","to Assyria",77,87]]},"7:12":{"text":"When they shall go, I will spread my net upon them; I will bring them down as the fowls of the heaven; I will chastise them, as their congregation hath heard.","words":[["H3212","When they shall go",0,18],["H6566","I will spread",20,33],["H7568","my net",34,40],["H3381","upon them; I will bring them down",41,74],["H5775","as the fowls",75,87],["H8064","of the heaven",88,101],["H3256","I will chastise",103,118],["H5712","them, as their congregation",119,146],["H8088","hath heard",147,157]]},"7:13":{"text":"Woe unto them! for they have fled from me: destruction unto them! because they have transgressed against me: though I have redeemed them, yet they have spoken lies against me.","words":[["H0188","Woe",0,3],["H5074","unto them! for they have fled",4,33],["H7701","from me: destruction",34,54],["H6586","unto them! because they have transgressed",55,96],["H6299","against me: though I have redeemed",97,131],["H1696","them, yet they have spoken",132,158],["H3577","lies",159,163]]},"7:14":{"text":"And they have not cried unto me with their heart, when they howled upon their beds: they assemble themselves for corn and wine, and they rebel against me.","words":[["H2199","And they have not cried",0,23],["H3820","unto me with their heart",24,48],["H3213","when they howled",50,66],["H4904","upon their beds",67,82],["H1481","they assemble",84,97],["H1715","themselves for corn",98,117],["H8492","and wine",118,126],["H5493","and they rebel",128,142]]},"7:15":{"text":"Though I have bound and strengthened their arms, yet do they imagine mischief against me.","words":[["H3256","Though I have bound",0,19],["H2388","and strengthened",20,36],["H2220","their arms",37,47],["H2803","yet do they imagine",49,68],["H7451","mischief",69,77]]},"7:16":{"text":"They return, but not to the most High: they are like a deceitful bow: their princes shall fall by the sword for the rage of their tongue: this shall be their derision in the land of Egypt.","words":[["H7725","They return",0,11],["H5920","but not to the most High",13,37],["H7423","they are like a deceitful",39,64],["H7198","bow",65,68],["H8269","their princes",70,83],["H5307","shall fall",84,94],["H2719","by the sword",95,107],["H2195","for the rage",108,120],["H3956","of their tongue",121,136],["H2097","this",138,142],["H3933","shall be their derision",143,166],["H0776","in the land",167,178],["H4714","of Egypt",179,187]]},"8:1":{"text":"Set the trumpet to thy mouth. He shall come as an eagle against the house of the LORD, because they have transgressed my covenant, and trespassed against my law.","words":[["H7782","Set the trumpet",0,15],["H2441","to thy mouth",16,28],["H5404","He shall come as an eagle",30,55],["H1004","against the house",56,73],["H3068","of the LORD",74,85],["H5674","because they have transgressed",87,117],["H1285","my covenant",118,129],["H6586","and trespassed",131,145],["H8451","against my law",146,160]]},"8:2":{"text":"Israel shall cry unto me, My God, we know thee.","words":[["H3478","Israel",0,6],["H2199","shall cry",7,16],["H0430","unto me, My God",17,32],["H3045","we know",34,41]]},"8:3":{"text":"Israel hath cast off the thing that is good: the enemy shall pursue him.","words":[["H3478","Israel",0,6],["H2186","hath cast off",7,20],["H2896","the thing that is good",21,43],["H0341","the enemy",45,54],["H7291","shall pursue",55,67]]},"8:4":{"text":"They have set up kings, but not by me: they have made princes, and I knew it not: of their silver and their gold have they made them idols, that they may be cut off.","words":[["H4427","They have set up kings",0,22],["H7786","but not by me: they have made princes",24,61],["H3045","and I knew",63,73],["H3701","it not: of their silver",74,97],["H2091","and their gold",98,112],["H6213","have they made",113,127],["H6091","them idols",128,138],["H3772","that they may be cut off",140,164]]},"8:5":{"text":"Thy calf, O Samaria, hath cast thee off; mine anger is kindled against them: how long will it be ere they attain to innocency?","words":[["H5695","Thy calf",0,8],["H8111","O Samaria",10,19],["H2186","hath cast",21,30],["H0639","thee off; mine anger",31,51],["H2734","is kindled",52,62],["H3808","against them: how long will it be ere",63,100],["H3201","they attain",101,112],["H5356","to innocency",113,125]]},"8:6":{"text":"For from Israel was it also: the workman made it; therefore it is not God: but the calf of Samaria shall be broken in pieces.","words":[["H3478","For from Israel",0,15],["H2796","was it also: the workman",16,40],["H6213","made",41,45],["H0430","it; therefore it is not God",46,73],["H5695","but the calf",75,87],["H8111","of Samaria",88,98],["H7616","shall be broken in pieces",99,124]]},"8:7":{"text":"For they have sown the wind, and they shall reap the whirlwind: it hath no stalk: the bud shall yield no meal: if so be it yield, the strangers shall swallow it up.","words":[["H2232","For they have sown",0,18],["H7307","the wind",19,27],["H7114","and they shall reap",29,48],["H5492","the whirlwind",49,62],["H7054","it hath no stalk",64,80],["H6780","the bud",82,89],["H6213","shall yield",90,101],["H7058","no meal",102,109],["H0194","if",111,113],["H6213","so be it yield",114,128],["H2114","the strangers",130,143],["H1104","shall swallow it up",144,163]]},"8:8":{"text":"Israel is swallowed up: now shall they be among the Gentiles as a vessel wherein is no pleasure.","words":[["H3478","Israel",0,6],["H1104","is swallowed up",7,22],["H1471","now shall they be among the Gentiles",24,60],["H3627","as a vessel",61,72],["H2656","wherein is no pleasure",73,95]]},"8:9":{"text":"For they are gone up to Assyria, a wild ass alone by himself: Ephraim hath hired lovers.","words":[["H5927","For they are gone up",0,20],["H0804","to Assyria",21,31],["H6501","a wild ass",33,43],["H0909","alone",44,49],["H0669","by himself: Ephraim",50,69],["H8566","hath hired",70,80],["H0158","lovers",81,87]]},"8:10":{"text":"Yea, though they have hired among the nations, now will I gather them, and they shall sorrow a little for the burden of the king of princes.","words":[["H8566","Yea, though they have hired",0,27],["H1471","among the nations",28,45],["H6908","now will I gather",47,64],["H2490","them, and they shall sorrow",65,92],["H4592","a little",93,101],["H4853","for the burden",102,116],["H4428","of the king",117,128],["H8269","of princes",129,139]]},"8:11":{"text":"Because Ephraim hath made many altars to sin, altars shall be unto him to sin.","words":[["H0669","Because Ephraim",0,15],["H7235","hath made many",16,30],["H4196","altars",31,37],["H2398","to sin",38,44],["H4196","altars",46,52],["H2398","shall be unto him to sin",53,77]]},"8:12":{"text":"I have written to him the great things of my law, but they were counted as a strange thing.","words":[["H3789","I have written",0,14],["H7230","to him the great things",15,38],["H7239","to him the great things",15,38],["H8451","of my law",39,48],["H2803","but they were counted",50,71],["H2114","as a strange thing",72,90]]},"8:13":{"text":"They sacrifice flesh for the sacrifices of mine offerings, and eat it; but the LORD accepteth them not; now will he remember their iniquity, and visit their sins: they shall return to Egypt.","words":[["H2076","They sacrifice",0,14],["H1320","flesh",15,20],["H2077","for the sacrifices",21,39],["H1890","of mine offerings",40,57],["H0398","and eat",59,66],["H3068","it; but the LORD",67,83],["H7521","accepteth",84,93],["H2142","them not; now will he remember",94,124],["H5771","their iniquity",125,139],["H6485","and visit",141,150],["H2403","their sins",151,161],["H7725","they shall return",163,180],["H4714","to Egypt",181,189]]},"8:14":{"text":"For Israel hath forgotten his Maker, and buildeth temples; and Judah hath multiplied fenced cities: but I will send a fire upon his cities, and it shall devour the palaces thereof.","words":[["H3478","For Israel",0,10],["H7911","hath forgotten",11,25],["H6213","his Maker",26,35],["H1129","and buildeth",37,49],["H1964","temples",50,57],["H3063","and Judah",59,68],["H7235","hath multiplied",69,84],["H1219","fenced",85,91],["H5892","cities",92,98],["H7971","but I will send",100,115],["H0784","a fire",116,122],["H5892","upon his cities",123,138],["H0398","and it shall devour",140,159],["H0759","the palaces",160,171]]},"9:1":{"text":"Rejoice not, O Israel, for joy, as other people: for thou hast gone a whoring from thy God, thou hast loved a reward upon every cornfloor.","words":[["H8055","Rejoice",0,7],["H3478","not, O Israel",8,21],["H1524","for joy",23,30],["H5971","as other people",32,47],["H2181","for thou hast gone a whoring",49,77],["H0430","from thy God",78,90],["H0157","thou hast loved",92,107],["H0868","a reward",108,116],["H1637","upon every cornfloor",117,137],["H1715","upon every cornfloor",117,137]]},"9:2":{"text":"The floor and the winepress shall not feed them, and the new wine shall fail in her.","words":[["H1637","The floor",0,9],["H3342","and the winepress",10,27],["H7462","shall not feed",28,42],["H8492","them, and the new wine",43,65],["H3584","shall fail",66,76]]},"9:3":{"text":"They shall not dwell in the LORD'S land; but Ephraim shall return to Egypt, and they shall eat unclean things in Assyria.","words":[["H3427","They shall not dwell",0,20],["H3068","in the LORD'S",21,34],["H0776","land",35,39],["H0669","but Ephraim",41,52],["H7725","shall return",53,65],["H4714","to Egypt",66,74],["H0398","and they shall eat",76,94],["H2931","unclean",95,102],["H0804","things in Assyria",103,120]]},"9:4":{"text":"They shall not offer wine offerings to the LORD, neither shall they be pleasing unto him: their sacrifices shall be unto them as the bread of mourners; all that eat thereof shall be polluted: for their bread for their soul shall not come into the house of the LORD.","words":[["H5258","They shall not offer",0,20],["H3196","wine",21,25],["H3068","offerings to the LORD",26,47],["H6149","neither shall they be pleasing",49,79],["H2077","unto him: their sacrifices",80,106],["H3899","shall be unto them as the bread",107,138],["H0205","of mourners",139,150],["H0398","all that eat",152,164],["H2930","thereof shall be polluted",165,190],["H3899","for their bread",192,207],["H5315","for their soul",208,222],["H0935","shall not come",223,237],["H1004","into the house",238,252],["H3068","of the LORD",253,264]]},"9:5":{"text":"What will ye do in the solemn day, and in the day of the feast of the LORD?","words":[["H6213","What will ye do",0,15],["H4150","in the solemn",16,29],["H3117","day",30,33],["H3117","and in the day",35,49],["H2282","of the feast",50,62],["H3068","of the LORD",63,74]]},"9:6":{"text":"For, lo, they are gone because of destruction: Egypt shall gather them up, Memphis shall bury them: the pleasant places for their silver, nettles shall possess them: thorns shall be in their tabernacles.","words":[["H1980","For, lo, they are gone",0,22],["H7701","because of destruction",23,45],["H4714","Egypt",47,52],["H6908","shall gather them up",53,73],["H4644","Memphis",75,82],["H6912","shall bury",83,93],["H4261","them: the pleasant",94,112],["H3701","places for their silver",113,136],["H7057","nettles",138,145],["H3423","shall possess",146,159],["H2336","them: thorns",160,172],["H0168","shall be in their tabernacles",173,202]]},"9:7":{"text":"The days of visitation are come, the days of recompence are come; Israel shall know it: the prophet is a fool, the spiritual man is mad, for the multitude of thine iniquity, and the great hatred.","words":[["H3117","The days",0,8],["H6486","of visitation",9,22],["H0935","are come",23,31],["H3117","the days",33,41],["H7966","of recompence",42,55],["H0935","are come",56,64],["H3478","Israel",66,72],["H3045","shall know",73,83],["H5030","it: the prophet",84,99],["H0191","is a fool",100,109],["H7307","the spiritual",111,124],["H0376","man",125,128],["H7696","is mad",129,135],["H7230","for the multitude",137,154],["H5771","of thine iniquity",155,172],["H7227","and the great",174,187],["H4895","hatred",188,194]]},"9:8":{"text":"The watchman of Ephraim was with my God: but the prophet is a snare of a fowler in all his ways, and hatred in the house of his God.","words":[["H6822","The watchman",0,12],["H0669","of Ephraim",13,23],["H0430","was with my God",24,39],["H5030","but the prophet",41,56],["H6341","is a snare",57,67],["H3352","of a fowler",68,79],["H1870","in all his ways",80,95],["H4895","and hatred",97,107],["H1004","in the house",108,120],["H0430","of his God",121,131]]},"9:9":{"text":"They have deeply corrupted themselves, as in the days of Gibeah: therefore he will remember their iniquity, he will visit their sins.","words":[["H6009","They have deeply",0,16],["H7843","corrupted",17,26],["H3117","themselves, as in the days",27,53],["H1390","of Gibeah",54,63],["H2142","therefore he will remember",65,91],["H5771","their iniquity",92,106],["H6485","he will visit",108,121],["H2403","their sins",122,132]]},"9:10":{"text":"I found Israel like grapes in the wilderness; I saw your fathers as the firstripe in the fig tree at her first time: but they went to Baalpeor, and separated themselves unto that shame; and their abominations were according as they loved.","words":[["H4672","I found",0,7],["H3478","Israel",8,14],["H6025","like grapes",15,26],["H4057","in the wilderness",27,44],["H7200","I saw",46,51],["H0001","your fathers",52,64],["H1063","as the firstripe",65,81],["H8384","in the fig tree",82,97],["H7225","at her first time",98,115],["H0935","but they went",117,130],["H1187","to Baalpeor",131,142],["H5144","and separated",144,157],["H1322","themselves unto that shame",158,184],["H8251","and their abominations",186,208],["H0157","were according as they loved",209,237]]},"9:11":{"text":"As for Ephraim, their glory shall fly away like a bird, from the birth, and from the womb, and from the conception.","words":[["H0669","As for Ephraim",0,14],["H3519","their glory",16,27],["H5774","shall fly away",28,42],["H5775","like a bird",43,54],["H3205","from the birth",56,70],["H0990","and from the womb",72,89],["H2032","and from the conception",91,114]]},"9:12":{"text":"Though they bring up their children, yet will I bereave them, that there shall not be a man left: yea, woe also to them when I depart from them!","words":[["H1431","Though they bring up",0,20],["H1121","their children",21,35],["H7921","yet will I bereave",37,55],["H0120","them, that there shall not be a man",56,91],["H0188","left: yea, woe",92,106],["H5493","also to them when I depart",107,133]]},"9:13":{"text":"Ephraim, as I saw Tyrus, is planted in a pleasant place: but Ephraim shall bring forth his children to the murderer.","words":[["H0669","Ephraim",0,7],["H7200","as I saw",9,17],["H6865","Tyrus",18,23],["H8362","is planted",25,35],["H5116","in a pleasant place",36,55],["H0669","but Ephraim",57,68],["H3318","shall bring forth",69,86],["H1121","his children",87,99],["H2026","to the murderer",100,115]]},"9:14":{"text":"Give them, O LORD: what wilt thou give? give them a miscarrying womb and dry breasts.","words":[["H5414","Give",0,4],["H3068","them, O LORD",5,17],["H5414","what wilt thou give",19,38],["H5414","give",40,44],["H7921","them a miscarrying",45,63],["H7358","womb",64,68],["H6784","and dry",69,76],["H7699","breasts",77,84]]},"9:15":{"text":"All their wickedness is in Gilgal: for there I hated them: for the wickedness of their doings I will drive them out of mine house, I will love them no more: all their princes are revolters.","words":[["H7451","All their wickedness",0,20],["H1537","is in Gilgal",21,33],["H8130","for there I hated",35,52],["H7455","them: for the wickedness",53,77],["H4611","of their doings",78,93],["H1644","I will drive them out",94,115],["H1004","of mine house",116,129],["H0160","I will love",131,142],["H3254","them no more",143,155],["H8269","all their princes",157,174],["H5637","are revolters",175,188]]},"9:16":{"text":"Ephraim is smitten, their root is dried up, they shall bear no fruit: yea, though they bring forth, yet will I slay even the beloved fruit of their womb.","words":[["H0669","Ephraim",0,7],["H5221","is smitten",8,18],["H8328","their root",20,30],["H3001","is dried up",31,42],["H6213","they shall bear",44,59],["H6529","no fruit",60,68],["H3205","yea, though they bring forth",70,98],["H4191","yet will I slay",100,115],["H4261","even the beloved",116,132],["H0990","fruit of their womb",133,152]]},"9:17":{"text":"My God will cast them away, because they did not hearken unto him: and they shall be wanderers among the nations.","words":[["H0430","My God",0,6],["H3988","will cast them away",7,26],["H8085","because they did not hearken",28,56],["H5074","unto him: and they shall be wanderers",57,94],["H1471","among the nations",95,112]]},"10:1":{"text":"Israel is an empty vine, he bringeth forth fruit unto himself: according to the multitude of his fruit he hath increased the altars; according to the goodness of his land they have made goodly images.","words":[["H3478","Israel",0,6],["H1238","is an empty",7,18],["H1612","vine",19,23],["H7737","he bringeth forth",25,42],["H6529","fruit",43,48],["H7230","unto himself: according to the multitude",49,89],["H6529","of his fruit",90,102],["H7235","he hath increased",103,120],["H4196","the altars",121,131],["H2896","according to the goodness",133,158],["H0776","of his land",159,170],["H2895","they have made goodly",171,192],["H4676","images",193,199]]},"10:2":{"text":"Their heart is divided; now shall they be found faulty: he shall break down their altars, he shall spoil their images.","words":[["H3820","Their heart",0,11],["H2505","is divided",12,22],["H0816","now shall they be found faulty",24,54],["H6202","he shall break down",56,75],["H4196","their altars",76,88],["H7703","he shall spoil",90,104],["H4676","their images",105,117]]},"10:3":{"text":"For now they shall say, We have no king, because we feared not the LORD; what then should a king do to us?","words":[["H0559","For now they shall say",0,22],["H4428","We have no king",24,39],["H3372","because we feared",41,58],["H3068","not the LORD",59,71],["H4428","what then should a king",73,96],["H6213","do",97,99]]},"10:4":{"text":"They have spoken words, swearing falsely in making a covenant: thus judgment springeth up as hemlock in the furrows of the field.","words":[["H1696","They have spoken",0,16],["H1697","words",17,22],["H0422","swearing",24,32],["H7723","falsely",33,40],["H3772","in making",41,50],["H1285","a covenant",51,61],["H4941","thus judgment",63,76],["H6524","springeth up",77,89],["H7219","as hemlock",90,100],["H8525","in the furrows",101,115],["H7704","of the field",116,128]]},"10:5":{"text":"The inhabitants of Samaria shall fear because of the calves of Bethaven: for the people thereof shall mourn over it, and the priests thereof that rejoiced on it, for the glory thereof, because it is departed from it.","words":[["H7934","The inhabitants",0,15],["H8111","of Samaria",16,26],["H1481","shall fear",27,37],["H5697","because of the calves",38,59],["H1007","of Bethaven",60,71],["H5971","for the people",73,87],["H0056","thereof shall mourn",88,107],["H3649","over it, and the priests",108,132],["H1523","thereof that rejoiced",133,154],["H3519","on it, for the glory",155,175],["H1540","thereof, because it is departed",176,207]]},"10:6":{"text":"It shall be also carried unto Assyria for a present to king Jareb: Ephraim shall receive shame, and Israel shall be ashamed of his own counsel.","words":[["H2986","It shall be also carried",0,24],["H0804","unto Assyria",25,37],["H4503","for a present",38,51],["H4428","to king",52,59],["H3377","Jareb",60,65],["H0669","Ephraim",67,74],["H3947","shall receive",75,88],["H1317","shame",89,94],["H3478","and Israel",96,106],["H0954","shall be ashamed",107,123],["H6098","of his own counsel",124,142]]},"10:7":{"text":"As for Samaria, her king is cut off as the foam upon the water.","words":[["H8111","As for Samaria",0,14],["H4428","her king",16,24],["H1820","is cut off",25,35],["H7110","as the foam",36,47],["H6440","upon",48,52],["H4325","the water",53,62]]},"10:8":{"text":"The high places also of Aven, the sin of Israel, shall be destroyed: the thorn and the thistle shall come up on their altars; and they shall say to the mountains, Cover us; and to the hills, Fall on us.","words":[["H1116","The high places",0,15],["H0206","also of Aven",16,28],["H2403","the sin",30,37],["H3478","of Israel",38,47],["H8045","shall be destroyed",49,67],["H6975","the thorn",69,78],["H1863","and the thistle",79,94],["H5927","shall come up",95,108],["H4196","on their altars",109,124],["H0559","and they shall say",126,144],["H2022","to the mountains",145,161],["H3680","Cover",163,168],["H1389","us; and to the hills",169,189],["H5307","Fall",191,195]]},"10:9":{"text":"O Israel, thou hast sinned from the days of Gibeah: there they stood: the battle in Gibeah against the children of iniquity did not overtake them.","words":[["H3478","O Israel",0,8],["H2398","thou hast sinned",10,26],["H3117","from the days",27,40],["H1390","of Gibeah",41,50],["H5975","there they stood",52,68],["H4421","the battle",70,80],["H1390","in Gibeah",81,90],["H1121","against the children",91,111],["H5932","of iniquity",112,123],["H5381","did not overtake",124,140]]},"10:10":{"text":"It is in my desire that I should chastise them; and the people shall be gathered against them, when they shall bind themselves in their two furrows.","words":[["H0185","It is in my desire",0,18],["H3256","that I should chastise",19,41],["H5971","them; and the people",42,62],["H0622","shall be gathered",63,80],["H0631","against them, when they shall bind",81,115],["H8147","themselves in their two",116,139],["H5869","furrows",140,147]]},"10:11":{"text":"And Ephraim is as an heifer that is taught, and loveth to tread out the corn; but I passed over upon her fair neck: I will make Ephraim to ride; Judah shall plow, and Jacob shall break his clods.","words":[["H0669","And Ephraim",0,11],["H5697","is as an heifer",12,27],["H3925","that is taught",28,42],["H0157","and loveth",44,54],["H1758","to tread out",55,67],["H5674","the corn; but I passed over",68,95],["H2898","upon her fair",96,109],["H6677","neck",110,114],["H0669","I will make Ephraim",116,135],["H7392","to ride",136,143],["H3063","Judah",145,150],["H2790","shall plow",151,161],["H3290","and Jacob",163,172],["H7702","shall break his clods",173,194]]},"10:12":{"text":"Sow to yourselves in righteousness, reap in mercy; break up your fallow ground: for it is time to seek the LORD, till he come and rain righteousness upon you.","words":[["H2232","Sow",0,3],["H6666","to yourselves in righteousness",4,34],["H7114","reap",36,40],["H6310","in",41,43],["H2617","mercy",44,49],["H5214","break up",51,59],["H5215","your fallow ground",60,78],["H6256","for it is time",80,94],["H1875","to seek",95,102],["H3068","the LORD",103,111],["H0935","till he come",113,125],["H3384","and rain",126,134],["H6664","righteousness",135,148]]},"10:13":{"text":"Ye have plowed wickedness, ye have reaped iniquity; ye have eaten the fruit of lies: because thou didst trust in thy way, in the multitude of thy mighty men.","words":[["H2790","Ye have plowed",0,14],["H7562","wickedness",15,25],["H7114","ye have reaped",27,41],["H5766","iniquity",42,50],["H0398","ye have eaten",52,65],["H6529","the fruit",66,75],["H3585","of lies",76,83],["H0982","because thou didst trust",85,109],["H1870","in thy way",110,120],["H7230","in the multitude",122,138],["H1368","of thy mighty men",139,156]]},"10:14":{"text":"Therefore shall a tumult arise among thy people, and all thy fortresses shall be spoiled, as Shalman spoiled Betharbel in the day of battle: the mother was dashed in pieces upon her children.","words":[["H7588","Therefore shall a tumult",0,24],["H6965","arise",25,30],["H5971","among thy people",31,47],["H4013","and all thy fortresses",49,71],["H7703","shall be spoiled",72,88],["H8020","as Shalman",90,100],["H7701","spoiled",101,108],["H1009","Betharbel",109,118],["H3117","in the day",119,129],["H4421","of battle",130,139],["H0517","the mother",141,151],["H7376","was dashed in pieces",152,172],["H1121","upon her children",173,190]]},"10:15":{"text":"So shall Bethel do unto you because of your great wickedness: in a morning shall the king of Israel utterly be cut off.","words":[["H3602","So",0,2],["H1008","shall Bethel",3,15],["H6213","do",16,18],["H6440","unto you because",19,35],["H7451","of your great",36,49],["H7451","wickedness",50,60],["H7837","in a morning",62,74],["H4428","shall the king",75,89],["H3478","of Israel",90,99],["H1820","utterly",100,107],["H1820","be cut off",108,118]]},"11:1":{"text":"When Israel was a child, then I loved him, and called my son out of Egypt.","words":[["H3478","When Israel",0,11],["H5288","was a child",12,23],["H0157","then I loved",25,37],["H7121","him, and called",38,53],["H1121","my son",54,60],["H4714","out of Egypt",61,73]]},"11:2":{"text":"As they called them, so they went from them: they sacrificed unto Baalim, and burned incense to graven images.","words":[["H7121","As they called",0,14],["H1980","them, so they went",15,33],["H6440","from them",34,43],["H2076","they sacrificed",45,60],["H1168","unto Baalim",61,72],["H6999","and burned incense",74,92],["H6456","to graven images",93,109]]},"11:3":{"text":"I taught Ephraim also to go, taking them by their arms; but they knew not that I healed them.","words":[["H8637","I taught",0,8],["H0669","Ephraim",9,16],["H8637","also to go",17,27],["H3947","taking",29,35],["H2220","them by their arms",36,54],["H3045","but they knew",56,69],["H7495","not that I healed",70,87]]},"11:4":{"text":"I drew them with cords of a man, with bands of love: and I was to them as they that take off the yoke on their jaws, and I laid meat unto them.","words":[["H4900","I drew",0,6],["H2256","them with cords",7,22],["H0120","of a man",23,31],["H5688","with bands",33,43],["H0160","of love",44,51],["H7311","and I was to them as they that take off",53,92],["H5923","the yoke",93,101],["H3895","on their jaws",102,115],["H5186","and I laid",117,127],["H0398","meat",128,132]]},"11:5":{"text":"He shall not return into the land of Egypt, but the Assyrian shall be his king, because they refused to return.","words":[["H7725","He shall not return",0,19],["H0776","into the land",20,33],["H4714","of Egypt",34,42],["H0804","but the Assyrian",44,60],["H4428","shall be his king",61,78],["H3985","because they refused",80,100],["H7725","to return",101,110]]},"11:6":{"text":"And the sword shall abide on his cities, and shall consume his branches, and devour them, because of their own counsels.","words":[["H2719","And the sword",0,13],["H2342","shall abide",14,25],["H5892","on his cities",26,39],["H3615","and shall consume",41,58],["H0905","his branches",59,71],["H0398","and devour",73,83],["H4156","them, because of their own counsels",84,119]]},"11:7":{"text":"And my people are bent to backsliding from me: though they called them to the most High, none at all would exalt him.","words":[["H5971","And my people",0,13],["H8511","are bent",14,22],["H4878","to backsliding",23,37],["H7121","from me: though they called",38,65],["H5920","them to the most High",66,87],["H3162","none at all",89,100],["H7311","would exalt",101,112]]},"11:8":{"text":"How shall I give thee up, Ephraim? how shall I deliver thee, Israel? how shall I make thee as Admah? how shall I set thee as Zeboim? mine heart is turned within me, my repentings are kindled together.","words":[["H5414","How shall I give thee up",0,24],["H0669","Ephraim",26,33],["H4042","how shall I deliver",35,54],["H3478","thee, Israel",55,67],["H5414","how shall I make",69,85],["H0126","thee as Admah",86,99],["H7760","how shall I set",101,116],["H6636","thee as Zeboim",117,131],["H3820","mine heart",133,143],["H2015","is turned",144,153],["H5150","within me, my repentings",154,178],["H3648","are kindled",179,190],["H3162","together",191,199]]},"11:9":{"text":"I will not execute the fierceness of mine anger, I will not return to destroy Ephraim: for I am God, and not man; the Holy One in the midst of thee: and I will not enter into the city.","words":[["H6213","I will not execute",0,18],["H2740","the fierceness",19,33],["H0639","of mine anger",34,47],["H7725","I will not return",49,66],["H7843","to destroy",67,77],["H0669","Ephraim",78,85],["H0410","for I am God",87,99],["H0376","and not man",101,112],["H6918","the Holy One",114,126],["H7130","in the midst",127,139],["H0935","of thee: and I will not enter",140,169],["H5892","into the city",170,183]]},"11:10":{"text":"They shall walk after the LORD: he shall roar like a lion: when he shall roar, then the children shall tremble from the west.","words":[["H3212","They shall walk",0,15],["H0310","after",16,21],["H3068","the LORD",22,30],["H7580","he shall roar",32,45],["H0738","like a lion",46,57],["H7580","when he shall roar",59,77],["H1121","then the children",79,96],["H2729","shall tremble",97,110],["H3220","from the west",111,124]]},"11:11":{"text":"They shall tremble as a bird out of Egypt, and as a dove out of the land of Assyria: and I will place them in their houses, saith the LORD.","words":[["H2729","They shall tremble",0,18],["H6833","as a bird",19,28],["H4714","out of Egypt",29,41],["H3123","and as a dove",43,56],["H0776","out of the land",57,72],["H0804","of Assyria",73,83],["H3427","and I will place",85,101],["H1004","them in their houses",102,122],["H5002","saith",124,129],["H3068","the LORD",130,138]]},"11:12":{"text":"Ephraim compasseth me about with lies, and the house of Israel with deceit: but Judah yet ruleth with God, and is faithful with the saints.","words":[["H0669","Ephraim",0,7],["H5437","compasseth",8,18],["H3585","me about with lies",19,37],["H1004","and the house",39,52],["H3478","of Israel",53,62],["H4820","with deceit",63,74],["H3063","but Judah",76,85],["H7300","yet ruleth",86,96],["H0410","with God",97,105],["H0539","and is faithful",107,122],["H6918","with the saints",123,138]]},"12:1":{"text":"Ephraim feedeth on wind, and followeth after the east wind: he daily increaseth lies and desolation; and they do make a covenant with the Assyrians, and oil is carried into Egypt.","words":[["H0669","Ephraim",0,7],["H7462","feedeth",8,15],["H7307","on wind",16,23],["H7291","and followeth",25,38],["H6921","after the east wind",39,58],["H3117","he daily",60,68],["H7235","increaseth",69,79],["H3577","lies",80,84],["H7701","and desolation",85,99],["H3772","and they do make",101,117],["H1285","a covenant",118,128],["H0804","with the Assyrians",129,147],["H8081","and oil",149,156],["H2986","is carried",157,167],["H4714","into Egypt",168,178]]},"12:2":{"text":"The LORD hath also a controversy with Judah, and will punish Jacob according to his ways; according to his doings will he recompense him.","words":[["H3068","The LORD",0,8],["H7379","hath also a controversy",9,32],["H3063","with Judah",33,43],["H6485","and will punish",45,60],["H3290","Jacob",61,66],["H1870","according to his ways",67,88],["H4611","according to his doings",90,113],["H7725","will he recompense",114,132]]},"12:3":{"text":"He took his brother by the heel in the womb, and by his strength he had power with God:","words":[["H0251","He took his brother",0,19],["H6117","by the heel",20,31],["H0990","in the womb",32,43],["H0202","and by his strength",45,64],["H8280","he had power",65,77],["H0430","with God",78,86]]},"12:4":{"text":"Yea, he had power over the angel, and prevailed: he wept, and made supplication unto him: he found him in Bethel, and there he spake with us;","words":[["H7786","Yea, he had power",0,17],["H4397","over the angel",18,32],["H3201","and prevailed",34,47],["H1058","he wept",49,56],["H2603","and made supplication",58,79],["H4672","unto him: he found",80,98],["H1008","him in Bethel",99,112],["H1696","and there he spake",114,132]]},"12:5":{"text":"Even the LORD God of hosts; the LORD is his memorial.","words":[["H3068","Even the LORD",0,13],["H0430","God",14,17],["H6635","of hosts",18,26],["H3068","the LORD",28,36],["H2143","is his memorial",37,52]]},"12:6":{"text":"Therefore turn thou to thy God: keep mercy and judgment, and wait on thy God continually.","words":[["H7725","Therefore turn",0,14],["H0430","thou to thy God",15,30],["H8104","keep",32,36],["H2617","mercy",37,42],["H4941","and judgment",43,55],["H6960","and wait",57,65],["H0430","on thy God",66,76],["H8548","continually",77,88]]},"12:7":{"text":"He is a merchant, the balances of deceit are in his hand: he loveth to oppress.","words":[["H3667","He is a merchant",0,16],["H3976","the balances",18,30],["H4820","of deceit",31,40],["H3027","are in his hand",41,56],["H0157","he loveth",58,67],["H6231","to oppress",68,78]]},"12:8":{"text":"And Ephraim said, Yet I am become rich, I have found me out substance: in all my labours they shall find none iniquity in me that were sin.","words":[["H0669","And Ephraim",0,11],["H0559","said",12,16],["H6238","Yet I am become rich",18,38],["H4672","I have found me out",40,59],["H0202","substance",60,69],["H3018","in all my labours",71,88],["H4672","they shall find",89,104],["H5771","none iniquity",105,118],["H2399","in me that were sin",119,138]]},"12:9":{"text":"And I that am the LORD thy God from the land of Egypt will yet make thee to dwell in tabernacles, as in the days of the solemn feast.","words":[["H3068","And I that am the LORD",0,22],["H0430","thy God",23,30],["H0776","from the land",31,44],["H4714","of Egypt",45,53],["H3427","will yet make thee to dwell",54,81],["H0168","in tabernacles",82,96],["H3117","as in the days",98,112],["H4150","of the solemn feast",113,132]]},"12:10":{"text":"I have also spoken by the prophets, and I have multiplied visions, and used similitudes, by the ministry of the prophets.","words":[["H1696","I have also spoken",0,18],["H5030","by the prophets",19,34],["H7235","and I have multiplied",36,57],["H2377","visions",58,65],["H1819","and used similitudes",67,87],["H3027","by the ministry",89,104],["H5030","of the prophets",105,120]]},"12:11":{"text":"Is there iniquity in Gilead? surely they are vanity: they sacrifice bullocks in Gilgal; yea, their altars are as heaps in the furrows of the fields.","words":[["H0205","Is there iniquity",0,17],["H1568","in Gilead",18,27],["H7723","surely they are vanity",29,51],["H2076","they sacrifice",53,67],["H7794","bullocks",68,76],["H1537","in Gilgal",77,86],["H4196","yea, their altars",88,105],["H1530","are as heaps",106,118],["H8525","in the furrows",119,133],["H7704","of the fields",134,147]]},"12:12":{"text":"And Jacob fled into the country of Syria, and Israel served for a wife, and for a wife he kept sheep.","words":[["H3290","And Jacob",0,9],["H1272","fled",10,14],["H7704","into the country",15,31],["H0758","of Syria",32,40],["H3478","and Israel",42,52],["H5647","served",53,59],["H0802","for a wife",60,70],["H0802","and for a wife",72,86],["H8104","he kept",87,94]]},"12:13":{"text":"And by a prophet the LORD brought Israel out of Egypt, and by a prophet was he preserved.","words":[["H5030","And by a prophet",0,16],["H3068","the LORD",17,25],["H5927","brought",26,33],["H3478","Israel",34,40],["H4714","out of Egypt",41,53],["H5030","and by a prophet",55,71],["H8104","was he preserved",72,88]]},"12:14":{"text":"Ephraim provoked him to anger most bitterly: therefore shall he leave his blood upon him, and his reproach shall his Lord return unto him.","words":[["H0669","Ephraim",0,7],["H3707","provoked him to anger",8,29],["H8563","most bitterly",30,43],["H5203","therefore shall he leave",45,69],["H1818","his blood",70,79],["H2781","upon him, and his reproach",80,106],["H0113","shall his Lord",107,121],["H7725","return",122,128]]},"13:1":{"text":"When Ephraim spake trembling, he exalted himself in Israel; but when he offended in Baal, he died.","words":[["H0669","When Ephraim",0,12],["H1696","spake",13,18],["H7578","trembling",19,28],["H5375","he exalted",30,40],["H3478","himself in Israel",41,58],["H0816","but when he offended",60,80],["H1168","in Baal",81,88],["H4191","he died",90,97]]},"13:2":{"text":"And now they sin more and more, and have made them molten images of their silver, and idols according to their own understanding, all of it the work of the craftsmen: they say of them, Let the men that sacrifice kiss the calves.","words":[["H2398","And now they sin",0,16],["H3254","more and more",17,30],["H6213","and have made",32,45],["H4541","them molten images",46,64],["H3701","of their silver",65,80],["H6091","and idols",82,91],["H8394","according to their own understanding",92,128],["H4639","all of it the work",130,148],["H2796","of the craftsmen",149,165],["H0559","they say",167,175],["H0120","of them, Let the men",176,196],["H2076","that sacrifice",197,211],["H5401","kiss",212,216],["H5695","the calves",217,227]]},"13:3":{"text":"Therefore they shall be as the morning cloud, and as the early dew that passeth away, as the chaff that is driven with the whirlwind out of the floor, and as the smoke out of the chimney.","words":[["H1242","Therefore they shall be as the morning",0,38],["H6051","cloud",39,44],["H7925","and as the early",46,62],["H2919","dew",63,66],["H1980","that passeth away",67,84],["H4671","as the chaff",86,98],["H5590","that is driven with the whirlwind",99,132],["H1637","out of the floor",133,149],["H6227","and as the smoke",151,167],["H0699","out of the chimney",168,186]]},"13:4":{"text":"Yet I am the LORD thy God from the land of Egypt, and thou shalt know no god but me: for there is no saviour beside me.","words":[["H3068","Yet I am the LORD",0,17],["H0430","thy God",18,25],["H0776","from the land",26,39],["H4714","of Egypt",40,48],["H3045","and thou shalt know",50,69],["H0430","no god",70,76],["H2108","but me",77,83],["H3467","for there is no saviour",85,108],["H1115","beside me",109,118]]},"13:5":{"text":"I did know thee in the wilderness, in the land of great drought.","words":[["H3045","I did know",0,10],["H4057","thee in the wilderness",11,33],["H0776","in the land",35,46],["H8514","of great drought",47,63]]},"13:6":{"text":"According to their pasture, so were they filled; they were filled, and their heart was exalted; therefore have they forgotten me.","words":[["H4830","According to their pasture",0,26],["H7646","so were they filled",28,47],["H7646","they were filled",49,65],["H3820","and their heart",67,82],["H7311","was exalted",83,94],["H7911","therefore have they forgotten",96,125]]},"13:7":{"text":"Therefore I will be unto them as a lion: as a leopard by the way will I observe them:","words":[["H7826","Therefore I will be unto them as a lion",0,39],["H5246","as a leopard",41,53],["H1870","by the way",54,64],["H7789","will I observe",65,79]]},"13:8":{"text":"I will meet them as a bear that is bereaved of her whelps, and will rend the caul of their heart, and there will I devour them like a lion: the wild beast shall tear them.","words":[["H6298","I will meet",0,11],["H1677","them as a bear",12,26],["H7909","that is bereaved",27,43],["H7167","of her whelps, and will rend",44,72],["H5458","the caul",73,81],["H3820","of their heart",82,96],["H0398","and there will I devour",98,121],["H3833","them like a lion",122,138],["H7704","the wild",140,148],["H2416","beast",149,154],["H1234","shall tear",155,165]]},"13:9":{"text":"O Israel, thou hast destroyed thyself; but in me is thine help.","words":[["H3478","O Israel",0,8],["H7843","thou hast destroyed",10,29],["H5828","thyself; but in me is thine help",30,62]]},"13:10":{"text":"I will be thy king: where is any other that may save thee in all thy cities? and thy judges of whom thou saidst, Give me a king and princes?","words":[["H0165","I will",0,6],["H4428","be thy king",7,18],["H0645","where",20,25],["H3467","is any other that may save",26,52],["H5892","thee in all thy cities",53,75],["H8199","and thy judges",77,91],["H0559","of whom thou saidst",92,111],["H5414","Give",113,117],["H4428","me a king",118,127],["H8269","and princes",128,139]]},"13:11":{"text":"I gave thee a king in mine anger, and took him away in my wrath.","words":[["H5414","I gave",0,6],["H4428","thee a king",7,18],["H0639","in mine anger",19,32],["H3947","and took",34,42],["H5678","him away in my wrath",43,63]]},"13:12":{"text":"The iniquity of Ephraim is bound up; his sin is hid.","words":[["H5771","The iniquity",0,12],["H0669","of Ephraim",13,23],["H6887","is bound up",24,35],["H2403","his sin",37,44],["H6845","is hid",45,51]]},"13:13":{"text":"The sorrows of a travailing woman shall come upon him: he is an unwise son; for he should not stay long in the place of the breaking forth of children.","words":[["H2256","The sorrows",0,11],["H3205","of a travailing woman",12,33],["H0935","shall come",34,44],["H2450","upon him: he is an unwise",45,70],["H1121","son",71,74],["H5975","for he should not stay",76,98],["H6256","long",99,103],["H4866","in the place of the breaking forth",104,138],["H1121","of children",139,150]]},"13:14":{"text":"I will ransom them from the power of the grave; I will redeem them from death: O death, I will be thy plagues; O grave, I will be thy destruction: repentance shall be hid from mine eyes.","words":[["H6299","I will ransom",0,13],["H3027","them from the power",14,33],["H7585","of the grave",34,46],["H1350","I will redeem",48,61],["H4194","them from death",62,77],["H4194","O death",79,86],["H0165","I will",88,94],["H1698","be thy plagues",95,109],["H7585","O grave",111,118],["H0165","I will",120,126],["H6987","be thy destruction",127,145],["H5164","repentance",147,157],["H5641","shall be hid",158,170],["H5869","from mine eyes",171,185]]},"13:15":{"text":"Though he be fruitful among his brethren, an east wind shall come, the wind of the LORD shall come up from the wilderness, and his spring shall become dry, and his fountain shall be dried up: he shall spoil the treasure of all pleasant vessels.","words":[["H6500","Though he be fruitful",0,21],["H0251","among his brethren",22,40],["H6921","an east wind",42,54],["H0935","shall come",55,65],["H7307","the wind",67,75],["H3068","of the LORD",76,87],["H5927","shall come up",88,101],["H4057","from the wilderness",102,121],["H4726","and his spring",123,137],["H0954","shall become dry",138,154],["H4599","and his fountain",156,172],["H2717","shall be dried up",173,190],["H8154","he shall spoil",192,206],["H0214","the treasure",207,219],["H2532","of all pleasant",220,235],["H3627","vessels",236,243]]},"13:16":{"text":"Samaria shall become desolate; for she hath rebelled against her God: they shall fall by the sword: their infants shall be dashed in pieces, and their women with child shall be ripped up.","words":[["H8111","Samaria",0,7],["H0816","shall become desolate",8,29],["H4784","for she hath rebelled",31,52],["H0430","against her God",53,68],["H5307","they shall fall",70,85],["H2719","by the sword",86,98],["H5768","their infants",100,113],["H7376","shall be dashed in pieces",114,139],["H2030","and their women with child",141,167],["H1234","shall be ripped up",168,186]]},"14:1":{"text":"O Israel, return unto the LORD thy God; for thou hast fallen by thine iniquity.","words":[["H3478","O Israel",0,8],["H7725","return",10,16],["H3068","unto the LORD",17,30],["H0430","thy God",31,38],["H3782","for thou hast fallen",40,60],["H5771","by thine iniquity",61,78]]},"14:2":{"text":"Take with you words, and turn to the LORD: say unto him, Take away all iniquity, and receive us graciously: so will we render the calves of our lips.","words":[["H3947","Take",0,4],["H1697","with you words",5,19],["H7725","and turn",21,29],["H3068","to the LORD",30,41],["H0559","say",43,46],["H5375","unto him, Take away",47,66],["H5771","all iniquity",67,79],["H3947","and receive",81,92],["H2896","us graciously",93,106],["H7999","so will we render",108,125],["H6499","the calves",126,136],["H8193","of our lips",137,148]]},"14:3":{"text":"Asshur shall not save us; we will not ride upon horses: neither will we say any more to the work of our hands, Ye are our gods: for in thee the fatherless findeth mercy.","words":[["H0804","Asshur",0,6],["H3467","shall not save",7,21],["H7392","us; we will not ride",22,42],["H5483","upon horses",43,54],["H0559","neither will we say",56,75],["H4639","any more to the work",76,96],["H3027","of our hands",97,109],["H0430","Ye are our gods",111,126],["H3490","for in thee the fatherless",128,154],["H7355","findeth mercy",155,168]]},"14:4":{"text":"I will heal their backsliding, I will love them freely: for mine anger is turned away from him.","words":[["H7495","I will heal",0,11],["H4878","their backsliding",12,29],["H0157","I will love",31,42],["H5071","them freely",43,54],["H0639","for mine anger",56,70],["H7725","is turned away",71,85]]},"14:5":{"text":"I will be as the dew unto Israel: he shall grow as the lily, and cast forth his roots as Lebanon.","words":[["H2919","I will be as the dew",0,20],["H3478","unto Israel",21,32],["H6524","he shall grow",34,47],["H7799","as the lily",48,59],["H5221","and cast forth",61,75],["H8328","his roots",76,85],["H3844","as Lebanon",86,96]]},"14:6":{"text":"His branches shall spread, and his beauty shall be as the olive tree, and his smell as Lebanon.","words":[["H3127","His branches",0,12],["H3212","shall spread",13,25],["H1935","and his beauty",27,41],["H2132","shall be as the olive tree",42,68],["H7381","and his smell",70,83],["H3844","as Lebanon",84,94]]},"14:7":{"text":"They that dwell under his shadow shall return; they shall revive as the corn, and grow as the vine: the scent thereof shall be as the wine of Lebanon.","words":[["H3427","They that dwell",0,15],["H6738","under his shadow",16,32],["H7725","shall return",33,45],["H2421","they shall revive",47,64],["H1715","as the corn",65,76],["H6524","and grow",78,86],["H1612","as the vine",87,98],["H2143","the scent",100,109],["H3196","thereof shall be as the wine",110,138],["H3844","of Lebanon",139,149]]},"14:8":{"text":"Ephraim shall say, What have I to do any more with idols? I have heard him, and observed him: I am like a green fir tree. From me is thy fruit found.","words":[["H0669","Ephraim",0,7],["H6091","shall say, What have I to do any more with idols",8,56],["H6030","I have heard",58,70],["H7789","him, and observed",71,88],["H7488","him: I am like a green",89,111],["H1265","fir tree",112,120],["H6529","From me is thy fruit",122,142],["H4672","found",143,148]]},"14:9":{"text":"Who is wise, and he shall understand these things? prudent, and he shall know them? for the ways of the LORD are right, and the just shall walk in them: but the transgressors shall fall therein.","words":[["H2450","Who is wise",0,11],["H0995","and he shall understand",13,36],["H0995","these things? prudent",37,58],["H3045","and he shall know",60,77],["H1870","them? for the ways",78,96],["H3068","of the LORD",97,108],["H3477","are right",109,118],["H6662","and the just",120,132],["H3212","shall walk",133,143],["H6586","in them: but the transgressors",144,174],["H3782","shall fall",175,185]]}}};
